INSERT INTO "public"."downtime_categories" ("id", "code", "name", "category", "description", "is_planned", "active", "sort_order") VALUES ('0b2f25d2-1eb5-4999-a279-b832462e595a', 'DT-012', 'Tunggu Instruksi / WO', 'Method', 'Operator menunggu instruksi kerja, Work Order, atau konfirmasi dari PPIC/Leader.', false, true, 240), ('1f3da13e-e7d8-43d3-bfa3-a0a3bc2631aa', 'DT-008', 'Kalibrasi Alat / Gauge', 'Machine', 'Kalibrasi atau verifikasi alat ukur, gauge, atau sensor.', true, true, 150), ('21c24a0c-84b9-4b52-978f-9a4d321b6968', 'DT-004', 'Machine Breakdown', 'Machine', 'Kerusakan mesin mendadak yang menyebabkan lini berhenti. Panggil maintenance.', false, true, 110), ('25654982-059a-4484-8414-d26a58d12ed5', 'DT-007', 'Setup / Adjustment Mesin', 'Machine', 'Penyetelan parameter mesin (suhu, tekanan, kecepatan) di luar changeover produk.', true, true, 140), ('337497f2-26d9-4a39-b03a-51bc450e50e4', 'DT-019', 'Suhu Ruangan Ekstrem', 'Environment', 'Suhu lingkungan di luar batas toleransi produksi (terlalu panas/dingin).', false, true, 430), ('391e6d34-3924-420d-84d8-dd3b2a7d3292', 'DT-010', 'Quality Hold / Stop & Check', 'Method', 'Lini dihentikan untuk inspeksi kualitas massal akibat temuan NG di lini.', false, true, 220), ('3a465160-8488-478f-b43d-feb03df7ab8f', 'DT-017', 'Pemadaman Listrik (PLN/Genset)', 'Environment', 'Gangguan pasokan listrik dari PLN atau kegagalan genset backup.', false, true, 410), ('3fbee9ec-5b40-4bab-a713-fb4ebbb21964', 'DT-003', 'Istirahat / Toilet Break', 'Man', 'Break personal operator di luar jadwal istirahat resmi.', true, true, 30), ('8701688f-f56b-4810-8b69-63f3749604de', 'DT-005', 'Fixture / Jig / Tool Rusak', 'Machine', 'Fixture, jig, atau perkakas rusak/aus sehingga proses tidak dapat berjalan.', false, true, 120), ('88fa1e28-d16f-4285-b76d-750d574d6885', 'DT-015', 'Salah Material / Wrong Part', 'Material', 'Material atau part yang diterima tidak sesuai spesifikasi atau part number.', false, true, 330), ('8f4f076d-089f-47ee-a54f-67a44eea0f92', 'DT-009', 'Changeover / Ganti Produk', 'Method', 'Setup pergantian produk: ganti jig, program, parameter, dan verifikasi 1st article.', true, true, 210), ('93ad2528-2655-41a9-b420-465b0ac8aac8', 'DT-011', 'Engineering Change (ECN)', 'Method', 'Perubahan desain atau proses dari Engineering — lini stop selama implementasi.', false, true, 230), ('9b139205-8907-4e56-bc0f-9df318a2eb02', 'DT-014', 'Material Defect / Reject', 'Material', 'Material incoming rejected oleh QC; proses berhenti menunggu material pengganti.', false, true, 320), ('9eebd3bf-3c0e-4ab9-a7d3-73f7fb8afae0', 'DT-001', 'Operator Absen / Kurang', 'Man', 'Jumlah operator tidak sesuai plan; perlu pengganti atau penyesuaian lini.', false, true, 10), ('aff90715-f60a-4eb4-9c01-1676c3f141d5', 'DT-020', 'Gangguan Fasilitas Lainnya', 'Environment', 'Masalah fasilitas lain: kebocoran atap, kebakaran kecil, evakuasi, dll.', false, true, 440), ('b1c983ac-8f7a-4a91-b19d-3399f3fcfb5f', 'DT-018', 'Gangguan Udara / Kompresor', 'Environment', 'Tekanan angin kompresor turun atau compressor breakdown.', false, true, 420), ('b403ec6e-71b9-4fe7-95a1-9dae4688c237', 'DT-006', 'Preventive Maintenance (PM)', 'Machine', 'Perawatan berkala terjadwal — lini berhenti sesuai jadwal PM.', true, true, 130), ('e44f60ac-255c-4116-b605-ccf2f138934b', 'DT-002', 'Operator Training / OJT', 'Man', 'Waktu henti untuk pelatihan, OJT, atau sertifikasi operator di lini.', true, true, 20), ('f8a192fc-3b1e-48d9-8748-addfab6a3480', 'DT-016', 'Stok Material Habis', 'Material', 'Buffer stok material di lini habis sebelum resupply tiba.', false, true, 340), ('ff7707be-4030-432a-9432-38f120daf1ef', 'DT-013', 'Tunggu Material / Part', 'Material', 'Material atau komponen belum tiba di lini; menunggu pengiriman dari warehouse.', false, true, 310);